mapper.select:
select Classroom_ID as classroomId, Classroom_Type as classroomType, Classroom_Cap as classroomCap, Classroom_State as classroomState, Classroom_Name as classroomName from classroom
and Classroom_Name like concat('%', #{classroomName}, '%')
and Classroom_Type = #{classroomType}
order by Classroom_ID limit #{offset}, #{pageSize}

select count(*) from classroom
and Classroom_Name like concat('%', #{classroomName}, '%')
and Classroom_Type = #{classroomType}
